<?php
if (!function_exists('hr_t')) {
  function hr_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('hr_h')) {
  function hr_h($key, $fallback = '') { return htmlspecialchars((string) hr_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('hr_js')) {
  function hr_js($key, $fallback = '') { return json_encode(hr_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
if(session_status()===PHP_SESSION_NONE)session_start();include "../../inc/config.php";session_check_json();
function md_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
$draw=isset($_POST['draw'])?(int)$_POST['draw']:1;$start=isset($_POST['start'])?max(0,(int)$_POST['start']):0;$len=isset($_POST['length'])?(int)$_POST['length']:25;if($len<=0||$len>500)$len=25;
$from=isset($_POST['tgl_awal'])&&$_POST['tgl_awal']!==''?$_POST['tgl_awal']:date('Y-m-01');$to=isset($_POST['tgl_akhir'])&&$_POST['tgl_akhir']!==''?$_POST['tgl_akhir']:date('Y-m-d');$status=isset($_POST['approval_status'])?trim($_POST['approval_status']):'';$type=isset($_POST['mutation_type'])?trim($_POST['mutation_type']):'';$kw=isset($_POST['keyword'])?trim($_POST['keyword']):'';
$p=array($from,$to);$w=" WHERE m.mutation_date BETWEEN ? AND ? ";if($status!==''){$w.=" AND m.approval_status=? ";$p[]=$status;}if($type!==''){$w.=" AND m.mutation_type=? ";$p[]=$type;}if($kw!==''){$like='%'.$kw.'%';$w.=" AND (m.mutation_no LIKE ? OR e.employee_no LIKE ? OR e.full_name LIKE ? OR m.reason_text LIKE ?) ";for($i=0;$i<4;$i++)$p[]=$like;}
$k=$db->fetch("SELECT COUNT(*) total,SUM(approval_status='DRAFT') draft,SUM(approval_status='SUBMITTED') submitted,SUM(approval_status='POSTED') posted FROM erp_employee_mutation");
$cnt=$db->fetch("SELECT COUNT(*) jml FROM erp_employee_mutation m JOIN erp_employee_master e ON e.id=m.employee_id $w",$p);$total=$cnt?(int)$cnt->jml:0;
$rows=$db->query("SELECT m.*,e.employee_no,e.full_name,od.nm_dept old_dept,nd.nm_dept new_dept,oj.job_title_code old_job,nj.job_title_code new_job FROM erp_employee_mutation m JOIN erp_employee_master e ON e.id=m.employee_id LEFT JOIN dept od ON od.kd_dept=m.old_department_code LEFT JOIN dept nd ON nd.kd_dept=m.new_department_code LEFT JOIN erp_job_title oj ON oj.id=m.old_job_title_id LEFT JOIN erp_job_title nj ON nj.id=m.new_job_title_id $w ORDER BY m.mutation_date DESC,m.id DESC LIMIT $start,$len",$p);
$data=array();$no=$start+1;foreach($rows as $r){$cls=$r->approval_status==='POSTED'?'success':($r->approval_status==='DRAFT'?'default':'info');$act='<div class="mm-action"><button class="btn btn-info btn-xs btn-mm-detail" data-id="'.(int)$r->id.'"><i class="fa fa-eye"></i></button> ';if($r->approval_status!=='POSTED'){$act.='<button class="btn btn-primary btn-xs btn-mm-edit" data-id="'.(int)$r->id.'"><i class="fa fa-pencil"></i></button> <button class="btn btn-success btn-xs btn-mm-post" data-id="'.(int)$r->id.'" data-no="'.md_h($r->mutation_no).'"><i class="fa fa-check"></i></button> <button class="btn btn-danger btn-xs btn-mm-delete" data-id="'.(int)$r->id.'" data-no="'.md_h($r->mutation_no).'"><i class="fa fa-trash"></i></button>';} $act.='</div>';$data[]=array($no++,$act,'<strong>'.md_h($r->mutation_no).'</strong><br><small>'.md_h($r->mutation_date).' / Eff '.md_h($r->effective_date).'</small>','<strong>'.md_h($r->employee_no).'</strong><br><small>'.md_h($r->full_name).'</small>',md_h($r->mutation_type).'<br><small>'.md_h($r->reason_code?:'-').'</small>','<strong>'.md_h($r->old_department_code?:'-').'</strong> '.md_h($r->old_dept?:'').'<br><i class="fa fa-arrow-down"></i><br><strong>'.md_h($r->new_department_code?:'-').'</strong> '.md_h($r->new_dept?:''),md_h($r->old_job?:'-').'<br><i class="fa fa-arrow-down"></i><br>'.md_h($r->new_job?:'-'),md_h($r->old_cost_center_code?:'-').' / '.md_h($r->old_pay_grade?:'-').'<br><i class="fa fa-arrow-down"></i><br>'.md_h($r->new_cost_center_code?:'-').' / '.md_h($r->new_pay_grade?:'-'),'<span class="label label-'.$cls.'">'.md_h($r->approval_status).'</span>',md_h($r->created_by?:'-').'<br><small>'.md_h($r->updated_by?:'-').'</small>');}
header('Content-Type: application/json');echo json_encode(array('draw'=>$draw,'recordsTotal'=>$total,'recordsFiltered'=>$total,'data'=>$data,'kpi'=>array('total'=>$k?(int)$k->total:0,'draft'=>$k?(int)$k->draft:0,'submitted'=>$k?(int)$k->submitted:0,'posted'=>$k?(int)$k->posted:0)));
?>
